// Verify /api/weather returns 400 when only lat is provided (lon missing → NaN)
async function testWeatherPartialParams() {
  const res = await fetch('http://localhost:3001/api/weather?lat=45');
  assertEquals(res.status, 400);
  const body = await res.json();
  assertEquals(body.error, true);
  assertEquals(body.message, 'lat and lon query parameters are required');
}

